import React, { useState, useEffect } from 'react';

// Navigation Component
function Navigation({ scrollToSection, menuOpen, setMenuOpen }) {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 100);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`navigation ${scrolled ? 'scrolled' : ''}`}>
      <div className="nav-container">
        <div className="logo" onClick={() => scrollToSection('hero')}>
          <span className="logo-text">Jay Dabgar</span>
          <span className="logo-subtitle">Photography</span>
        </div>

        <ul className={`nav-links ${menuOpen ? 'open' : ''}`}>
          <li><button className='nav-link'><a href='/home' >Home</a></button></li>
          <li><button className='nav-link'><a href='/home' >About</a></button></li>
          <li><button className='nav-link'><a href='/home' >Portfolio</a></button></li>
          <li><button className='nav-link'><a href='/home' >Stories</a></button></li>
          <li><button className='nav-link'><a href='/home' >Services</a></button></li>
          <li><button className='nav-link nav-cta'><a href='/home' >Contact</a></button></li>
        </ul>


        <button className={`hamburger ${menuOpen ? 'open' : ''}`} onClick={() => setMenuOpen(!menuOpen)}>
          <span></span>
          <span></span>
          <span></span>
        </button>
      </div>
    </nav>
  );
}


export default Navigation
